#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

# Function to extract text from a PDF file
sub extract_text {
    my ($filename) = @_;
    my $pdf = PDF::API2->open($filename);
    my $pages = $pdf->pages;

    my $text = '';
    for my $page (1 .. $pages) {
        $text .= $pdf->page($page)->text;
    }

    return $text;
}

# Function to extract specific information (date, author, table)
sub extract_info {
    my ($text) = @_;
    my $info = {};

    # Regular expressions to find date, author, and table
    if ($text =~ /Date:\s*(\d{1,2}\/\d{1,2}\/\d{4})/) {
        $info->{date} = $1;
    }
    if ($text =~ /Author:\s*(\w+)/) {
        $info->{author} = $1;
    }
    if ($text =~ /Table:\s*(.*?)\s*(?=Date|\Author)/s) {
        $info->{table} = $1;
    }

    return $info;
}

